import * as React from 'react';
import { graphql, navigate } from 'gatsby';
import { GatsbyImage, getImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Layout from '../../components/layout';
import Link from '../../components/common/link';
import SectionMenu from '../../components/sections/menu';
import { Seo } from '../../components/seo';
import { works } from '../../libs/works';

const Page = props => {
  const param = new URLSearchParams(props.location.search);
  const category = param.get('category');

  const addImageData = ({ name, category, link }) => {
    const data = props.data.allFile.edges.filter(worksThumbnail => {
      return worksThumbnail.node.name === `${name}_00`;
    });

    if (!data || !data[0] || !data[0].node) {
      console.log(name);
      console.log(data);
      return false;
    }

    const node = data[0].node;

    return {
      name,
      category,
      link,
      image: getImage(node)
    };
  };

  const datas = works.map(work => {
    return addImageData(work);
  });

  return (
    <Layout>
      <SectionMenu />
      <Box
        py={10} // header 分
      >
        <Box
          mb={4} // thumbnail の spacing 分
          sx={{
            display: 'flex',
            justifyContent: 'center'
          }}
        >
          {['All', 'Hotel', 'Interior', 'Portrait', 'Snap'].map((label, i) => {
            const _category = label.toLowerCase();

            const link = `/works/${
              _category === 'all' ? '' : `?category=${_category}`
            }`;

            const isCurrent =
              (_category === 'all' && category === null) ||
              _category === category;

            return (
              <Link
                key={i}
                href={link}
                sx={{
                  mx: {
                    md: 4,
                    sm: 2,
                    xs: 1
                  },
                  textDecoration: isCurrent && 'underline',
                  pointerEvents: isCurrent && 'none'
                }}
                onClick={e => {
                  e.preventDefault();
                  navigate(link);
                }}
              >
                {label}
              </Link>
            );
          })}
        </Box>
        <Grid container direction='row' justifyContent='center' spacing={4}>
          {datas
            .filter(data => {
              const _category = data.category;

              // category:all
              if (!category) {
                return true;
              }

              return _category === category;
            })
            .map(({ name, link, image }, i) => {
              link += `/${category ? `?category=${category}` : ''}`;

              return (
                <Grid
                  item
                  key={i}
                  sx={{
                    transition: 'all 250ms ease-out'
                  }}
                >
                  <Link href={`/works/${link}`}>
                    <Box
                      sx={{
                        width: {
                          md: 200,
                          sm: 200,
                          xs: 150
                        },
                        height: {
                          md: 200,
                          sm: 200,
                          xs: 150
                        },
                        overflow: 'hidden',
                        transition: 'all 250ms ease-out'
                      }}
                    >
                      <GatsbyImage
                        image={image}
                        alt={name}
                        layout='fullWidth'
                        placeholder='blurred'
                        style={{
                          width: '100%',
                          height: '100%',
                          pointerEvents: 'none',
                          userSelect: 'none'
                        }}
                      />
                    </Box>
                  </Link>
                </Grid>
              );
            })}
        </Grid>
      </Box>
    </Layout>
  );
};

export default Page;

export const Head = () => <Seo title='WORKS' />;

export const query = graphql`
  {
    allFile(
      filter: {
        relativeDirectory: { eq: "works" }
        name: { regex: "/^.+_00$/" }
      }
    ) {
      edges {
        node {
          childImageSharp {
            gatsbyImageData(width: 400, placeholder: BLURRED)
          }
          name
        }
      }
    }
  }
`;
